  'changzhou/pagoda': ('معبد تياننينغ', 'يرتفع هذا المعبد في وسط المدينة ليصل إلى 153 متراً، مما يجعله أطول معبد في العالم.'),
  'changzhou/comb': ('حرفة الأمشاط', 'كانت أمشاط تشانغتشو المصنوعة يدوياً منذ آلاف السنين تُقدم كهدايا ملكية.'),
  'changzhou/canal': ('القناة الكبرى', 'يستمتع الزوار بالتنزه على ضفاف القناة لاستكشاف الأحياء القديمة ومشاهدة أضواء الليل.'),
  'shaoxing/wine': ('نبيذ شاوشينغ', 'يُصنع هنا منذ آلاف السنين نبيذ الأرز الأصفر الشهير الذي يُعد عنصراً أساسياً في المطبخ الصيني.'),
  'shaoxing/bridge': ('الجسور الحجرية', 'تحتفظ مدينة شاوشينغ، التي تتخللها القنوات المائية، بمئات الجسور الحجرية المقوسة.'),
  'shaoxing/pen': ('مهد الخط العربي الصيني', 'يُعتبر جناح الأوركيد الخاص بالخطاط الشهير وانغ شي تشي موقعاً مقدساً لفن الخط.'),
  'shaoxing/boat': ('قوارب ووبنغ', 'تُعد قوارب "ووبنغ" ذات المظلات السوداء، التي تُدفع بالأقدام، وسيلة التنقل الكلاسيكية في القنوات المائية.'),
  'bengbu/shell': ('ميناء اللؤلؤ', 'يعني اسم المدينة "رصيف المحار"، وقد اشتهرت قديماً بإنتاج لآلئ نهر هواي.'),
  'bengbu/train': ('بوابة السكك الحديدية', 'تُعد مدينة بنغبو نقطة عبور رئيسية لنهر هواي على خط السكك الحديدية بين الشمال والجنوب، وقد ازدهرت المدينة بفضل محطتها المركزية.'),
  'bengbu/river': ('نهر هواي', 'يُعتبر هذا النهر الفاصل الطبيعي والجغرافي بين شمال الصين وجنوبها، ويمر عبر مدينة بنغبو.'),
  'bengbu/blossom': ('مهرجانات الربيع', 'تكتسي المتنزهات الواقعة على ضفاف النهر بحلة زاهية خلال مهرجانات تفتح الزهور في فصل الربيع.'),
  'jiujiang/mountain': ('جبل لو', 'ألهمت قمم جبل لو الضبابية، المدرج ضمن قائمة اليونسكو للتراث العالمي، العديد من الشعراء والرسامين عبر التاريخ.'),
  'jiujiang/tea': ('شاي الضباب والسحاب', 'يُعد شاي "يون وو" الذي يُزرع على منحدرات جبل لو من بين أكثر أنواع الشاي الصيني دقةً ونقاءً.'),
  'jiujiang/lake': ('بحيرة بويانغ', 'تُعد بحيرة بويانغ أكبر بحيرة للمياه العذبة في الصين، وتستقبل آلاف الطيور المهاجرة خلال فصل الشتاء.'),
  'jiujiang/scroll': ('مدينة القصائد', 'خُطت أبيات الشعراء العظام مثل باي جويي وسو شي على بوابات هذه المدينة المطلة على النهر.'),
  'quanzhou/ship': ('طريق الحرير البحري', 'كانت مدينة تشوانتشو، المعروفة تاريخياً باسم "زيتون"، أعظم ميناء في العالم خلال العصور الوسطى وهي مدرجة ضمن قائمة اليونسكو.'),
  'quanzhou/mosque': ('مسجد تشينغجينغ', 'يُعد هذا المسجد الحجري الذي بُني عام 1009 ميلادي من أقدم المساجد التاريخية في الصين.'),
  'quanzhou/puppet': ('فن العرائس', 'يُعتبر فن تحريك العرائس بالخيوط في تشوانتشو تقليداً مسرحياً عريقاً يعود تاريخه إلى ألف عام.'),
  'quanzhou/tea': ('شاي تيغوانين', 'يُعرف شاي الأولونغ الذي يُنتج في منطقة أنشي المجاورة عالمياً باسم شاي "الإلهة الحديدية".'),
  'beijing/great-wall': ('سور الصين العظيم', 'يُعد أطول تحصين في العالم، حيث يمتد لأكثر من 20 ألف كيلومتر لحماية الحدود الشمالية للصين، وتعتبر منطقة بادالينغ بالقرب من بكين الجزء الأكثر زيارة بفضل درجاته الحجرية وأبراجه الدفاعية.'),
  'beijing/temple': ('معبد السماء', 'مجمع مقدس كان أباطرة أسرتي مينغ وتشينغ يصلون فيه سنوياً من أجل حصاد وفير، ويتميز بسقفه الأزرق الدائري المكون من ثلاث طبقات والذي بُني دون استخدام مسمار واحد.'),
  'beijing/pagoda': ('باغودا تياننينغ', 'برج حجري يعود لأسرة لياو، يبلغ ارتفاعه 57 متراً ويتكون من 13 طابقاً، ويُعد شاهداً على تاريخ بكين العريق بفضل نقوشه البارزة وتصميمه المثمن.'),
  'beijing/opera': ('أوبرا بكين', 'فن مسرحي صيني تقليدي يجمع بين الغناء والحوار والفنون القتالية، حيث تعبر ألوان أقنعة الممثلين عن شخصياتهم، فالأحمر يرمز للولاء والأبيض للمكر.'),
};
